mapper.select:
SELECT s.schedule_id, s.title, s.description, s.start_time, s.end_time, s.type, s.customer_id, c.company_name AS customer_name, s.contact_id, ct.name AS contact_name, s.location, s.create_user_id, u.realname AS create_user_name, s.create_time FROM crm_schedule s LEFT JOIN crm_customer c ON s.customer_id = c.customer_id LEFT JOIN crm_contact ct ON s.contact_id = ct.contact_id LEFT JOIN manager_user u ON s.create_user_id = u.user_id WHERE 1=1
AND s.customer_id = #{query.customerId}
AND s.type = #{query.type}
AND s.start_time >= #{query.startDate}
AND s.start_time <= #{query.endDate}
ORDER BY s.start_time DESC

SELECT s.schedule_id, s.title, s.description, s.start_time, s.end_time, s.type, s.customer_id, c.company_name AS customer_name, s.contact_id, ct.name AS contact_name, s.location, s.create_user_id, u.realname AS create_user_name, s.create_time FROM crm_schedule s LEFT JOIN crm_customer c ON s.customer_id = c.customer_id LEFT JOIN crm_contact ct ON s.contact_id = ct.contact_id LEFT JOIN manager_user u ON s.create_user_id = u.user_id WHERE s.create_user_id = #{userId}
AND DATE(s.start_time) = CURRENT_DATE
AND s.start_time >= #{today} AND s.start_time <= #{weekEnd}
ORDER BY s.start_time ASC
